-- Function to create notifications when order status changes\nCREATE OR REPLACE FUNCTION notify_order_status_change()\nRETURNS TRIGGER AS $$\nDECLARE\n    runner_name TEXT;\n    notification_title TEXT;\n    notification_message TEXT;\nBEGIN\n    -- Only proceed if status actually changed\n    IF OLD.status = NEW.status THEN\n        RETURN NEW;\n    END IF;\n\n    -- Get runner name if assigned\n    IF NEW.runner_id IS NOT NULL THEN\n        SELECT full_name INTO runner_name \n        FROM profiles \n        WHERE id = NEW.runner_id;\n    END IF;\n\n    -- Determine notification content based on new status\n    CASE NEW.status\n        WHEN 'accepted' THEN\n            notification_title := 'Order Accepted! 🎉';\n            notification_message := COALESCE(runner_name, 'A runner') || ' has accepted your order #' || RIGHT(NEW.id::text, 8) || '. They will start working on it soon.';\n        \n        WHEN 'in_progress' THEN\n            notification_title := 'Order In Progress 🚀';\n            notification_message := COALESCE(runner_name, 'Your runner') || ' has started working on your order #' || RIGHT(NEW.id::text, 8) || '.';\n        \n        WHEN 'completed' THEN\n            notification_title := 'Order Completed! ✅';\n            notification_message := 'Your order #' || RIGHT(NEW.id::text, 8) || ' has been completed' || \n                                  CASE WHEN runner_name IS NOT NULL THEN ' by ' || runner_name ELSE '' END || \n                                  '. Please check and confirm.';\n        \n        WHEN 'cancelled' THEN\n            notification_title := 'Order Cancelled ❌';\n            notification_message := 'Your order #' || RIGHT(NEW.id::text, 8) || ' has been cancelled.';\n        \n        ELSE\n            -- Don't create notification for other status changes\n            RETURN NEW;\n    END CASE;\n\n    -- Insert notification\n    INSERT INTO notifications (user_id, title, message, is_read)\n    VALUES (NEW.student_id, notification_title, notification_message, false);\n\n    RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Create trigger for order status changes\nDROP TRIGGER IF EXISTS order_status_notification_trigger ON orders;\nCREATE TRIGGER order_status_notification_trigger\n    AFTER UPDATE ON orders\n    FOR EACH ROW\n    EXECUTE FUNCTION notify_order_status_change();\n\n-- Function to create notification when runner is assigned\nCREATE OR REPLACE FUNCTION notify_runner_assigned()\nRETURNS TRIGGER AS $$\nDECLARE\n    runner_name TEXT;\nBEGIN\n    -- Only proceed if runner was just assigned (changed from NULL to a value)\n    IF OLD.runner_id IS NOT NULL OR NEW.runner_id IS NULL THEN\n        RETURN NEW;\n    END IF;\n\n    -- Get runner name\n    SELECT full_name INTO runner_name \n    FROM profiles \n    WHERE id = NEW.runner_id;\n\n    -- Insert notification\n    INSERT INTO notifications (user_id, title, message, is_read)\n    VALUES (\n        NEW.student_id, \n        'Runner Assigned! 👤', \n        COALESCE(runner_name, 'A runner') || ' has been assigned to your order #' || RIGHT(NEW.id::text, 8) || '.',\n        false\n    );\n\n    RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Create trigger for runner assignment\nDROP TRIGGER IF EXISTS runner_assignment_notification_trigger ON orders;\nCREATE TRIGGER runner_assignment_notification_trigger\n    AFTER UPDATE ON orders\n    FOR EACH ROW\n    EXECUTE FUNCTION notify_runner_assigned();\n\n-- Function to update order timestamps\nCREATE OR REPLACE FUNCTION update_order_timestamps()\nRETURNS TRIGGER AS $$\nBEGIN\n    -- Update accepted_at when status changes to accepted\n    IF OLD.status != 'accepted' AND NEW.status = 'accepted' THEN\n        NEW.accepted_at = NOW();\n    END IF;\n\n    -- Update completed_at when status changes to completed\n    IF OLD.status != 'completed' AND NEW.status = 'completed' THEN\n        NEW.completed_at = NOW();\n    END IF;\n\n    -- Always update updated_at\n    NEW.updated_at = NOW();\n\n    RETURN NEW;\nEND;\n$$ LANGUAGE plpgsql;\n\n-- Create trigger for updating timestamps\nDROP TRIGGER IF EXISTS order_timestamp_trigger ON orders;\nCREATE TRIGGER order_timestamp_trigger\n    BEFORE UPDATE ON orders\n    FOR EACH ROW\n    EXECUTE FUNCTION update_order_timestamps();\n\n-- Create index for better notification queries\nCREATE INDEX IF NOT EXISTS idx_notifications_user_unread ON notifications(user_id, is_read, created_at DESC);\n